mapper.select:
SELECT * FROM ( SELECT *, (6371 * acos( cos(radians(#{latitude})) * cos(radians(latitude)) * cos(radians(longitude) - radians(#{longitude})) + sin(radians(#{latitude})) * sin(radians(latitude)) )) AS distance FROM places WHERE 1=1
AND ( to_tsvector('simple', COALESCE(title, '') || ' ' || COALESCE(address, '') || ' ' || COALESCE(category, '') || ' ' || COALESCE(descriptions, '')) @@ plainto_tsquery('simple', #{keyword}) OR LOWER(title) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(address) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(category) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(descriptions) LIKE CONCAT('%', LOWER(#{keyword}), '%') )
AND category = #{category}
AND review_rating >= #{minRating}
) AS places_with_distance WHERE distance <= #{radius} ORDER BY distance LIMIT #{limit} OFFSET #{offset}
